code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Badge } from 'decantr/components';

code.example:
function QuickStartCards() {
  const { section, div, h2, p, h3, pre, button } = tags;

  return section({ class: css('_py30 _relative _z1') },
    div({ class: css('_container') },
      h2({ class: css('_heading2 _text[center] _mb4') }, 'Quick Start'),
      p({ class: css('_text[center] _fgmuted _mx[auto] _mb14') }, 'Three steps to get started.'),
      // Step cards row
      div({ class: css('_flex _gap6 _mw[920px] _mx[auto] _mb12') },
        // Step 1 - Config (coral gradient)
        Card({ class: css('_flex1 _rounded[16px] _p7 _relative _transition'), style: 'background:linear-gradient(135deg,#F58882,#D06060)' },
          Badge({ class: css('_w10 _h10 _rounded[50%] _flex _items[center] _justify[center] _fw700 _mb4 _bgblack/20 _fgwhite') }, '1'),
          h3({ class: css('_fw700 _mb3 _fgwhite') }, 'Configure'),
          pre({ class: css('_bgblack/30 _rounded[8px] _p3 _mono _fs[0.7rem] _lh[1.7] _fgwhite/85 _whitespace[pre]') }, 'npx decantr init\n# creates decantr.essence.json')
        ),
        // Step 2 - Prompt (amber gradient)
        Card({ class: css('_flex1 _rounded[16px] _p7 _relative _transition'), style: 'background:linear-gradient(135deg,#FDA303,#D08800)' },
          Badge({ class: css('_w10 _h10 _rounded[50%] _flex _items[center] _justify[center] _fw700 _mb4 _bgblack/20 _fgwhite') }, '2'),
          h3({ class: css('_fw700 _mb3 _fgwhite') }, 'Prompt'),
          div({ class: css('_bgblack/20 _rounded[10px_10px_10px_2px] _p4 _fs[0.82rem] _lh[1.5]') }, '"Build me a SaaS dashboard..."')
        ),
        // Step 3 - Build (purple gradient)
        Card({ class: css('_flex1 _rounded[16px] _p7 _relative _transition'), style: 'background:linear-gradient(135deg,#6500C6,#4A0090)' },
          Badge({ class: css('_w10 _h10 _rounded[50%] _flex _items[center] _justify[center] _fw700 _mb4 _bgblack/20 _fgwhite') }, '3'),
          h3({ class: css('_fw700 _mb3 _fgwhite') }, 'Build'),
          pre({ class: css('_bgblack/30 _rounded[8px] _p3 _mono _fs[0.68rem] _lh[1.7] _fgwhite/85 _whitespace[pre]') }, '✓ Theme applied\n✓ Structure validated\n✓ Guard active')
        )
      ),
      // Tabbed config section
      div({ class: css('_mw[640px] _mx[auto]') },
        div({ class: css('_flex _gap0 _mb[-1px] _relative _z1') },
          button({ class: css('_bgtransparent _border _border[rgba(255,255,255,0.1)] _borderbottom[none] _fgcyan _py2 _px5 _fs[0.82rem] _fw600 _rounded[8px_8px_0_0]') }, 'Claude'),
          button({ class: css('_bgtransparent _border _border[rgba(255,255,255,0.1)] _borderbottom[none] _fgmuted _py2 _px5 _fs[0.82rem] _fw600 _rounded[8px_8px_0_0]') }, 'Cursor')
        ),
        pre({ class: css('_bgcodebg _border _border[rgba(255,255,255,0.08)] _rounded[0_8px_8px_8px] _p5 _mono _fs[0.75rem] _lh[1.7] _fgmuted _overflow[auto] _whitespace[pre]') }, '// Framework-specific config here')
      )
    )
  );
}

